const { ethers } = require("ethers");
const fs = require("fs");
const path = require("path");

// Read the contract source
const contractPath = path.join(__dirname, "src/contracts/PropertyToken.sol");
const contractSource = fs.readFileSync(contractPath, "utf8");

async function main() {
  try {
    // Connect to local Hardhat node
    const provider = new ethers.JsonRpcProvider("http://127.0.0.1:8545/");
    const wallet = new ethers.Wallet("0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80", provider);
    
    console.log("Deploying from address:", wallet.address);
    
    // Deploy PropertyToken contract
    const PropertyTokenFactory = new ethers.ContractFactory(
      ["constructor(string memory name, string memory symbol, uint256 initialSupply, uint256 _tokenPrice)",
       "function buyTokens(uint256 amount) public payable",
       "function getTokenPrice() public view returns (uint256)",
       "function getAvailableTokens() public view returns (uint256)"],
      "",
      wallet
    );
    
    const propertyToken = await PropertyTokenFactory.deploy(
      "Ocean View Condo", // name
      "OVC",              // symbol
      ethers.parseEther("1000"),  // 1000 tokens
      ethers.parseEther("0.1")    // 0.1 ETH per token
    );
    
    await propertyToken.waitForDeployment();
    const contractAddress = await propertyToken.getAddress();
    
    console.log("PropertyToken deployed to:", contractAddress);
    
    // Update the mock data in server.js with the actual contract address
    const serverJsPath = path.join(__dirname, "server.js");
    let serverJs = fs.readFileSync(serverJsPath, "utf8");
    
    // Replace the mock contract address with the actual one
    serverJs = serverJs.replace(
      /contractAddress: '0x[0-9a-fA-F]{40}'/g,
      `contractAddress: '${contractAddress}'`
    );
    
    fs.writeFileSync(serverJsPath, serverJs);
    console.log("Updated server.js with the actual contract address");
    
    return contractAddress;
  } catch (error) {
    console.error("Deployment failed:", error);
    process.exit(1);
  }
}

main()
  .then(() => process.exit(0))
  .catch((error) => {
    console.error(error);
    process.exit(1);
  });
